export async function getBlogCollection(contentType: CollectionKey = 'blog') {
  return await getCollection(contentType, ({ data }: CollectionEntry<typeof contentType>) => {
    // Not in production & draft is not false
    return prod ? !data.draft : true
  })
}

export function injectAuthProviderRoutes(
	injectRoute: InjectRoute,
	providers: Array<{ routes?: Array<{ pattern: string; entrypoint: string }> }>,
): void {
	for (const provider of providers) {
		if (provider.routes) {
			for (const route of provider.routes) {
				injectRoute({
					pattern: route.pattern,
					entrypoint: route.entrypoint,
				});
			}
		}
	}
}

async function fetchCount(item: SubstatsItem) {
  if (!item.api) return
  try {
    const response = await fetch(`https://api.swo.moe/stats/${item.api}`)
    const data = await response.json()
    if (data.failed) {
      throw new Error(data.message)
    } else {
      item.count = data.count
    }
  } catch (error) {
    console.error(`Error in Substats fetching: ${error}`)
  }
}

export function cloudflareCache(
	config: CloudflareCacheConfig = {},
): CacheProviderConfig<CloudflareCacheConfig> {
	return {
		// Resolved by Vite/Astro at build time — points to the runtime module
		entrypoint: "@emdash-cms/cloudflare/cache",
		config,
	};
}

function collectionsHash(collections: IconCollection[]): string {
  const hash = createHash("sha256");
  for (const collection of collections) {
    hash.update(collection.prefix);
    hash.update(
      Object.keys(collection.icons)
        .concat(Object.keys(collection.aliases ?? {}))
        .sort()
        .join(","),
    );
  }
  return hash.digest("hex");
}

export function getLqipStyle(
	src: string,
	basePath?: string,
	isPublic?: boolean,
): string | undefined {
	if (isExternalImage(src)) return undefined;
	const gradient = getLqipGradient(src, basePath, isPublic);
	return gradient ? `background: ${gradient}` : undefined;
}

function buildGetRecordUrl(pds: string, did: string, collection: string, rkey: string): string {
	const url = new URL("/xrpc/com.atproto.sync.getRecord", pds);
	url.searchParams.set("did", did);
	url.searchParams.set("collection", collection);
	url.searchParams.set("rkey", rkey);
	return url.toString();
}

async fetch(request: Request, env: Env): Promise<Response> {
	const url = new URL(request.url);

	const apiResponse = await handleApi(request, url, env);
	if (apiResponse) return apiResponse;

	// Anything else falls through to Workers Assets for the dashboard.
	return new Response("Not found", { status: 404 });
}

async function handleLogout() {
	const res = await apiFetch("/_emdash/api/auth/logout?redirect=/_emdash/admin/login", {
		method: "POST",
		credentials: "same-origin",
	});
	if (res.redirected) {
		window.location.href = res.url;
	} else {
		window.location.href = "/_emdash/admin/login";
	}
}

export async function parseApiResponse<T>(
	response: Response,
	fallbackMessage = "Request failed",
): Promise<T> {
	if (!response.ok) await throwResponseError(response, fallbackMessage);
	const body: { data: T } = await response.json();
	return body.data;
}

export async function validateAccessJwt(
	jwt: string,
	config: AccessConfig,
): Promise<AccessJwtPayload> {
	const audience = resolveAudience(config);
	const issuer = `https://${config.teamDomain}`;
	const jwks = getJwks(config.teamDomain);

	const { payload } = await jwtVerify<AccessJwtPayload>(jwt, jwks, {
		issuer,
		audience,
		clockTolerance: 60, // 60 seconds clock skew tolerance
	});

	return payload;
}

export function unwrapResult<T>(result: ApiResult<T>, successStatus = 200): Response {
	if (!result.success) {
		return apiError(
			result.error.code,
			result.error.message,
			mapErrorStatus(result.error.code),
			result.error.details,
		);
	}
	return apiSuccess(result.data, successStatus);
}

async run({ args }) {
	configureOutputMode(args);
	try {
		const client = createClientFromArgs(args);
		await client.unpublish(args.collection, args.id);
		output({ success: true }, args);
		consola.success(`Unpublished ${args.collection}/${args.id}`);
	} catch (error) {
		consola.error(error instanceof Error ? error.message : "Unknown error");
		process.exit(1);
	}
}

