export function generateStorageModule(storageEntrypoint?: string): string {
	if (!storageEntrypoint) {
		return `export const createStorage = undefined;`;
	}
	return `
import { createStorage as _createStorage } from "${storageEntrypoint}";
export const createStorage = _createStorage;
`;
}

export function generateAuthModule(authEntrypoint?: string): string {
	if (!authEntrypoint) {
		return `export const authenticate = undefined;`;
	}
	return `
import { authenticate as _authenticate } from "${authEntrypoint}";
export const authenticate = _authenticate;
`;
}

async function resolveIdIncludingTrashed(
	repo: ContentRepository,
	collection: string,
	identifier: string,
	locale?: string,
): Promise<string | null> {
	const item = await repo.findByIdOrSlugIncludingTrashed(collection, identifier, locale);
	return item?.id ?? null;
}

export function drainBackfillDeadLetterBatch(
	batch: MessageBatchLike<BackfillJob>,
	_env: Env,
): void {
	for (const message of batch.messages) {
		console.error("[aggregator] backfill DLQ drain: pair exhausted retries", {
			did: message.body.did,
			collection: message.body.collection,
		});
		message.ack();
	}
}

export function findCurrentHeading(headings: HeadingItem[], cursorPos: number): HeadingItem | null {
	if (headings.length === 0) return null;

	// Find the heading that contains or precedes the cursor
	let current: HeadingItem | null = null;
	for (const heading of headings) {
		if (heading.pos <= cursorPos) {
			current = heading;
		} else {
			break;
		}
	}

	return current;
}

export async function createTarball(sourceDir: string, outputPath: string): Promise<void> {
	const { createGzip } = await import("node:zlib");
	const tarStream = packTar(sourceDir);
	const gzip = createGzip({ level: 9 });
	const out = createWriteStream(outputPath);
	await pipeline(tarStream, gzip, out);
}

export async function getEnvironmentKey(): Promise<CryptoKey> {
	// This should never happen, because we always check `hasEnvironmentKey` before this is called.
	if (!hasEnvironmentKey()) {
		throw new Error(
			`There is no environment key defined. If you see this error there is a bug in Astro.`,
		);
	}
	const encodedKey = getEncodedEnvironmentKey();
	return decodeKey(encodedKey);
}

addHighlightStyles(className) {
  if (!className)
    return;
  const styleElement = document.createElement("style");
  styleElement.innerText = `:where(.${className}) { background-color: yellow; color: black; }`;
  document.head.appendChild(styleElement);
}

function buildPluginBlockFormValues(
	block: PluginBlockDef | null,
	initialValues?: Record<string, unknown>,
): Record<string, unknown> {
	const defaults = getPluginBlockDefaultValues(block?.fields);
	return initialValues ? { ...defaults, ...initialValues } : defaults;
}

export async function listRegistryReleases(
	config: RegistryClientConfig,
	did: string,
	slug: string,
	opts?: { cursor?: string; limit?: number },
): Promise<ValidatedListReleases> {
	const client = await getDiscoveryClient(config);
	return client.listReleases(did, slug, opts);
}

function resolveEnvValue(explicit: string | undefined, envVarName: string): string | undefined {
	if (explicit) return explicit;
	if (!(envVarName in env)) return undefined;
	const value: unknown = Reflect.get(env, envVarName);
	return typeof value === "string" ? value : undefined;
}
